@barrettruth 

> Scheduling the redraw in `diagnostic.lua` also avoids the issue while being less wasteful, but probably shouldn't bother callers with this:


yeah that would defeat the purpose of the `nvim_exec_autocmds` change, which is intended to reduce manual steps :P

Here's a bit bigger minimal repro with few things added. Flickering happens randomly when doing edits.

```lua
local lsp_group = vim.api.nvim_create_augroup('vimrc_lsp', { clear = true })

vim.api.nvim_create_autocmd('FileType', {
  group = lsp_group,
  callback = function()
    local client = vim.lsp.start({
      name = 'ts_ls',
      cmd = { 'typescript-language-server', '--stdio' },
      root_dir = vim.uv.cwd(),
    })
    if client then
      vim.lsp.buf_attach_client(0, client)
    end
  end,
})

local function statusline_active()
  return '%#Function#ACTIVEWINDOW%*'
end

local function statusline_inactive()
  return [[ %f %m %= %y ]]
end

function _G.MyStatusline()
  local win_id = vim.fn.win_getid()
  local focus = vim.g.statusline_winid == win_id
  if focus then
    return statusline_active()
  end
  return statusline_inactive()
end

vim.diagnostic.config({
  virtual_text = false,
  float = {
    border = 'rounded',
    header = '',
    focusable = false,
  },
  severity_sort = true,
})

vim.api.nvim_create_autocmd('LspAttach', {
  group = lsp_group,
  callback = function(ev)
    local bufnr = ev.buf
    local client = vim.lsp.get_client_by_id(ev.data.client_id)
    if not client then return end

    if client:supports_method('textDocument/documentHighlight') then
      vim.api.nvim_create_autocmd({ 'CursorHold', 'CursorHoldI' }, {
        buffer = bufnr,
        callback = function()
          vim.lsp.buf.document_highlight()
        end,
        group = lsp_group,
      })
      vim.api.nvim_create_autocmd('CursorMoved', {
        buffer = bufnr,
        callback = function()
          vim.lsp.buf.clear_references()
        end,
        group = lsp_group,
      })
    end
  end,
})

vim.o.statusline = '%!v:lua.MyStatusline()'

```

